34	const componentGroupBase = (count: number): number => {
35	  const blocks = Math.floor(count / BLOCK_SIZE);
36	  const remainder = count % BLOCK_SIZE;
37	  return blocks * BLOCK_BASE + remainder * COMPONENT_BASE;
38	};
