40	const policyBasePremium = (items: Item[]): number => {
41	  let total = 0;
42	  const componentCounts: Record<string, number> = {};
43	  for (const item of items) {
44	    if (COMPONENT_TYPES.has(item.type)) {
45	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
46	    } else {
47	      total += MAIN_ITEM_BASE[item.type];
48	    }
49	  }
50	  for (const count of Object.values(componentCounts)) {
51	    total += componentGroupBase(count);
52	  }
