56	const quotePremium = (step: QuoteStep): number => {
57	  const base = policyBasePremium(step.items);
58	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE_RATE;
59	  return Math.ceil(withFirstInsurance) + PROCESSING_FEE;
60	};
